import axios, { type AxiosInstance, type AxiosRequestConfig } from 'axios';

let _tokenGetter: (() => string | null) | null = null;
let _tokenSetter: ((token: string | null) => void) | null = null;
let _refreshFn: (() => Promise<string | null>) | null = null;

export function configureClient(opts: {
  tokenGetter: () => string | null;
  tokenSetter: (token: string | null) => void;
  refreshFn: () => Promise<string | null>;
}) {
  _tokenGetter = opts.tokenGetter;
  _tokenSetter = opts.tokenSetter;
  _refreshFn = opts.refreshFn;
}

export function createApiClient(baseURL: string): AxiosInstance {
  const client = axios.create({
    baseURL,
    headers: { 'Content-Type': 'application/json' },
    timeout: 30_000,
  });

  client.interceptors.request.use((config) => {
    const token = _tokenGetter?.();
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  });

  let isRefreshing = false;
  let failedQueue: Array<{
    resolve: (token: string | null) => void;
    reject: (err: unknown) => void;
  }> = [];

  const processQueue = (error: unknown, token: string | null) => {
    failedQueue.forEach((p) => {
      if (error) p.reject(error);
      else p.resolve(token);
    });
    failedQueue = [];
  };

  client.interceptors.response.use(
    (res) => res,
    async (error) => {
      const originalRequest = error.config as AxiosRequestConfig & { _retry?: boolean };

      if (error.response?.status === 401 && !originalRequest._retry && _refreshFn) {
        if (isRefreshing) {
          return new Promise((resolve, reject) => {
            failedQueue.push({ resolve, reject });
          }).then((token) => {
            if (originalRequest.headers) {
              originalRequest.headers['Authorization'] = `Bearer ${token}`;
            }
            return client(originalRequest);
          });
        }

        originalRequest._retry = true;
        isRefreshing = true;

        try {
          const newToken = await _refreshFn();
          if (newToken) {
            _tokenSetter?.(newToken);
            processQueue(null, newToken);
            if (originalRequest.headers) {
              originalRequest.headers['Authorization'] = `Bearer ${newToken}`;
            }
            return client(originalRequest);
          }
        } catch (refreshError) {
          processQueue(refreshError, null);
          _tokenSetter?.(null);
          return Promise.reject(refreshError);
        } finally {
          isRefreshing = false;
        }
      }

      return Promise.reject(error);
    },
  );

  return client;
}

let _apiClient: AxiosInstance | null = null;

export function getApiClient(): AxiosInstance {
  if (!_apiClient) {
    throw new Error(
      'API client not initialized. Call initApiClient() first.',
    );
  }
  return _apiClient;
}

export function initApiClient(baseURL: string): AxiosInstance {
  _apiClient = createApiClient(baseURL);
  return _apiClient;
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';

import type {
  AuthTokens,
  LoginInput,
  OtpSendInput,
  OtpVerifyInput,
  RegisterInput,
  User,
} from '@roamera/types';

import { getApiClient } from '../client';

export const authKeys = {
  me: ['auth', 'me'] as const,
};

export function useMeQuery() {
  return useQuery({
    queryKey: authKeys.me,
    queryFn: async (): Promise<User> => {
      const { data } = await getApiClient().get('/api/v1/auth/me');
      return data.user;
    },
    retry: false,
    staleTime: 5 * 60 * 1000,
  });
}

export function useLogin() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (
      input: LoginInput,
    ): Promise<AuthTokens & { user: User }> => {
      const { data } = await getApiClient().post('/api/v1/auth/login', input);
      return data;
    },
    onSuccess: (data) => {
      queryClient.setQueryData(authKeys.me, data.user);
    },
  });
}

export function useRegister() {
  return useMutation({
    mutationFn: async (input: RegisterInput): Promise<{ message: string }> => {
      const { data } = await getApiClient().post('/api/v1/auth/register', input);
      return data;
    },
  });
}

export function useOtpSend() {
  return useMutation({
    mutationFn: async (input: OtpSendInput): Promise<{ message: string }> => {
      const { data } = await getApiClient().post('/api/v1/auth/otp/send', input);
      return data;
    },
  });
}

export function useOtpVerify() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (
      input: OtpVerifyInput,
    ): Promise<AuthTokens & { user: User }> => {
      const { data } = await getApiClient().post('/api/v1/auth/otp/verify', input);
      return data;
    },
    onSuccess: (data) => {
      queryClient.setQueryData(authKeys.me, data.user);
    },
  });
}

export function useLogout() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      await getApiClient().post('/api/v1/auth/logout');
    },
    onSuccess: () => {
      queryClient.clear();
    },
  });
}

export function useWsToken() {
  return useQuery({
    queryKey: ['auth', 'ws-token'],
    queryFn: async (): Promise<{ token: string }> => {
      const { data } = await getApiClient().get('/api/v1/auth/ws-token');
      return data;
    },
    staleTime: 9 * 60 * 1000,
  });
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';

import type { UpdateProfileInput, User } from '@roamera/types';

import { getApiClient } from '../client';

export const userKeys = {
  profile: (username: string) => ['users', username] as const,
  followers: (userId: string) => ['users', userId, 'followers'] as const,
  following: (userId: string) => ['users', userId, 'following'] as const,
  search: (q: string) => ['users', 'search', q] as const,
};

export function useUserQuery(username: string) {
  return useQuery({
    queryKey: userKeys.profile(username),
    queryFn: async (): Promise<User> => {
      const { data } = await getApiClient().get(`/api/v1/users/${username}`);
      return data.user;
    },
    enabled: !!username,
  });
}

export function useUpdateProfile() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (input: UpdateProfileInput): Promise<User> => {
      const { data } = await getApiClient().patch('/api/v1/users/me', input);
      return data.user;
    },
    onSuccess: (user) => {
      queryClient.setQueryData(['auth', 'me'], user);
      queryClient.invalidateQueries({ queryKey: userKeys.profile(user.username) });
    },
  });
}

export function useFollowUser() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ userId, action }: { userId: string; action: 'follow' | 'unfollow' }) => {
      if (action === 'follow') {
        await getApiClient().post(`/api/v1/users/${userId}/follow`);
      } else {
        await getApiClient().delete(`/api/v1/users/${userId}/follow`);
      }
    },
    onSuccess: (_data, { userId }) => {
      queryClient.invalidateQueries({ queryKey: ['users'] });
      queryClient.invalidateQueries({ queryKey: ['auth', 'me'] });
    },
  });
}

export function useUserSearch(q: string) {
  return useQuery({
    queryKey: userKeys.search(q),
    queryFn: async (): Promise<User[]> => {
      const { data } = await getApiClient().get('/api/v1/users/search', { params: { q } });
      return data.users;
    },
    enabled: q.length >= 2,
  });
}

type WsEventHandler = (payload: unknown) => void;

interface WsMessage {
  type: string;
  [key: string]: unknown;
}

interface SubscribeMessage {
  type: 'subscribe';
  rooms: string[];
  since?: number;
}

export class WsClient {
  private ws: WebSocket | null = null;
  private url: string;
  private rooms: Set<string> = new Set();
  private handlers: Map<string, Set<WsEventHandler>> = new Map();
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 10;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private lastEventTimestamps: Map<string, number> = new Map();
  private pingTimer: ReturnType<typeof setInterval> | null = null;
  private tokenGetter: () => Promise<string | null>;
  private isConnecting = false;

  constructor(opts: {
    baseUrl: string;
    tokenGetter: () => Promise<string | null>;
  }) {
    this.url = opts.baseUrl.replace(/^http/, 'ws');
    this.tokenGetter = opts.tokenGetter;
  }

  async connect(): Promise<void> {
    if (this.ws?.readyState === WebSocket.OPEN || this.isConnecting) return;

    this.isConnecting = true;
    const token = await this.tokenGetter();
    if (!token) {
      this.isConnecting = false;
      return;
    }

    const wsUrl = `${this.url}/ws?token=${encodeURIComponent(token)}`;
    this.ws = new WebSocket(wsUrl);

    this.ws.onopen = () => {
      this.isConnecting = false;
      this.reconnectAttempts = 0;
      this._startPing();
      if (this.rooms.size > 0) {
        this._send({
          type: 'subscribe',
          rooms: [...this.rooms],
          since: this._oldestTimestamp(),
        });
      }
    };

    this.ws.onmessage = (event) => {
      try {
        const msg = JSON.parse(event.data as string) as WsMessage;
        this.lastEventTimestamps.set(msg.type, Date.now());
        const handlers = this.handlers.get(msg.type);
        handlers?.forEach((h) => h(msg));
        const wildcardHandlers = this.handlers.get('*');
        wildcardHandlers?.forEach((h) => h(msg));
      } catch {
        // ignore malformed messages
      }
    };

    this.ws.onclose = () => {
      this.isConnecting = false;
      this._stopPing();
      this._scheduleReconnect();
    };

    this.ws.onerror = () => {
      this.isConnecting = false;
      this.ws?.close();
    };
  }

  subscribe(rooms: string[]): void {
    rooms.forEach((r) => this.rooms.add(r));
    if (this.ws?.readyState === WebSocket.OPEN) {
      this._send({ type: 'subscribe', rooms } as SubscribeMessage);
    }
  }

  unsubscribe(rooms: string[]): void {
    rooms.forEach((r) => this.rooms.delete(r));
    if (this.ws?.readyState === WebSocket.OPEN) {
      this._send({ type: 'unsubscribe', rooms });
    }
  }

  on(event: string, handler: WsEventHandler): () => void {
    if (!this.handlers.has(event)) {
      this.handlers.set(event, new Set());
    }
    this.handlers.get(event)!.add(handler);
    return () => this.off(event, handler);
  }

  off(event: string, handler: WsEventHandler): void {
    this.handlers.get(event)?.delete(handler);
  }

  disconnect(): void {
    if (this.reconnectTimer) clearTimeout(this.reconnectTimer);
    this._stopPing();
    this.ws?.close();
    this.ws = null;
    this.reconnectAttempts = 0;
  }

  get isConnected(): boolean {
    return this.ws?.readyState === WebSocket.OPEN;
  }

  private _send(data: unknown): void {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(data));
    }
  }

  private _startPing(): void {
    this._stopPing();
    this.pingTimer = setInterval(() => {
      this._send({ type: 'ping' });
    }, 25_000);
  }

  private _stopPing(): void {
    if (this.pingTimer) {
      clearInterval(this.pingTimer);
      this.pingTimer = null;
    }
  }

  private _scheduleReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) return;
    const delay = Math.min(1000 * 2 ** this.reconnectAttempts, 30_000);
    this.reconnectAttempts++;
    this.reconnectTimer = setTimeout(() => {
      void this.connect();
    }, delay);
  }

  private _oldestTimestamp(): number | undefined {
    if (this.lastEventTimestamps.size === 0) return undefined;
    return Math.min(...this.lastEventTimestamps.values());
  }
}

