import * as React from 'react';

type AvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';

interface AvatarProps {
  src?: string | null;
  alt?: string;
  size?: AvatarSize;
  username?: string;
  className?: string;
}

const sizeMap: Record<AvatarSize, string> = {
  xs: 'h-6 w-6 text-xs',
  sm: 'h-8 w-8 text-sm',
  md: 'h-10 w-10 text-base',
  lg: 'h-14 w-14 text-lg',
  xl: 'h-20 w-20 text-2xl',
};

function getInitials(username?: string): string {
  if (!username) return '?';
  const parts = username.split(/[_.\s]+/).filter(Boolean);
  if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
  return username.slice(0, 2).toUpperCase();
}

const bgColors = [
  'bg-teal-500',
  'bg-blue-500',
  'bg-purple-500',
  'bg-orange-500',
  'bg-rose-500',
  'bg-emerald-500',
];

function getColorIndex(username?: string): number {
  if (!username) return 0;
  let hash = 0;
  for (let i = 0; i < username.length; i++) {
    hash = username.charCodeAt(i) + ((hash << 5) - hash);
  }
  return Math.abs(hash) % bgColors.length;
}

export function Avatar({ src, alt, size = 'md', username, className = '' }: AvatarProps) {
  const sizeClass = sizeMap[size];
  const base = `inline-flex items-center justify-center rounded-full overflow-hidden shrink-0 ${sizeClass} ${className}`;

  if (src) {
    return (
      <img
        src={src}
        alt={alt ?? username ?? 'avatar'}
        className={`${base} object-cover`}
      />
    );
  }

  const colorClass = bgColors[getColorIndex(username)];
  return (
    <div className={`${base} ${colorClass} text-white font-semibold`}>
      {getInitials(username)}
    </div>
  );
}

import * as React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
  hint?: string;
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
  wrapperClassName?: string;
}

export const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ label, error, hint, leftIcon, rightIcon, wrapperClassName = '', className = '', ...props }, ref) => {
    const base =
      'w-full rounded-2xl border bg-white dark:bg-slate-900 px-4 py-2.5 text-slate-900 dark:text-slate-100 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-colors duration-150 disabled:opacity-50 disabled:cursor-not-allowed';
    const borderClass = error
      ? 'border-red-400 dark:border-red-500'
      : 'border-slate-200 dark:border-slate-700';
    const paddingLeft = leftIcon ? 'pl-10' : '';
    const paddingRight = rightIcon ? 'pr-10' : '';

    return (
      <div className={`flex flex-col gap-1 ${wrapperClassName}`}>
        {label && (
          <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
            {label}
          </label>
        )}
        <div className="relative">
          {leftIcon && (
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
              {leftIcon}
            </span>
          )}
          <input
            ref={ref}
            className={`${base} ${borderClass} ${paddingLeft} ${paddingRight} ${className}`}
            {...props}
          />
          {rightIcon && (
            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
              {rightIcon}
            </span>
          )}
        </div>
        {error && <p className="text-sm text-red-500">{error}</p>}
        {hint && !error && <p className="text-sm text-slate-500">{hint}</p>}
      </div>
    );
  },
);

Input.displayName = 'Input';

