import path from 'path';

import { createClient } from '@libsql/client';
import { migrate } from 'drizzle-orm/libsql/migrator';
import { drizzle } from 'drizzle-orm/libsql';

async function runMigrations() {
  const url = process.env.DATABASE_URL ?? 'file:data/app.db';

  // Ensure the data directory exists for local file mode
  if (url.startsWith('file:')) {
    const fs = await import('fs');
    const dbPath = url.replace('file:', '');
    const dir = path.dirname(dbPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  }

  const client = createClient({
    url,
    authToken: process.env.DATABASE_AUTH_TOKEN,
  });

  const db = drizzle(client);

  console.log('Running migrations...');
  await migrate(db, { migrationsFolder: './drizzle' });
  console.log('Migrations complete.');

  client.close();
}

runMigrations().catch((err) => {
  console.error('Migration failed:', err);
  process.exit(1);
});

import type { ErrorRequestHandler } from 'express';
import { ZodError } from 'zod';

import { logger } from '../lib/logger';

export const errorHandler: ErrorRequestHandler = (err, _req, res, _next) => {
  if (err instanceof ZodError) {
    res.status(400).json({
      success: false,
      error: 'Validation error',
      code: 'VALIDATION_ERROR',
      details: err.flatten().fieldErrors,
    });
    return;
  }

  const status = (err as { status?: number }).status ?? 500;
  const message = status < 500 ? err.message : 'Internal server error';

  if (status >= 500) {
    logger.error({ err }, 'Unhandled server error');
  }

  res.status(status).json({
    success: false,
    error: message,
    code: (err as { code?: string }).code ?? 'INTERNAL_ERROR',
  });
};

export class AppError extends Error {
  status: number;
  code: string;

  constructor(message: string, status = 400, code = 'APP_ERROR') {
    super(message);
    this.status = status;
    this.code = code;
  }
}

import type { NextFunction, Request, Response } from 'express';
import jwt from 'jsonwebtoken';

import { env } from '../lib/env';

export interface AuthRequest extends Request {
  user?: { id: string; role: string };
}

export function authenticate(req: AuthRequest, res: Response, next: NextFunction): void {
  const header = req.headers.authorization;
  if (!header?.startsWith('Bearer ')) {
    res.status(401).json({ success: false, error: 'Missing or invalid authorization header' });
    return;
  }

  const token = header.slice(7);
  try {
    const payload = jwt.verify(token, env.JWT_SECRET) as { sub: string; role: string };
    req.user = { id: payload.sub, role: payload.role };
    next();
  } catch {
    res.status(401).json({ success: false, error: 'Invalid or expired token' });
  }
}

export function requireAdmin(req: AuthRequest, res: Response, next: NextFunction): void {
  if (req.user?.role !== 'admin') {
    res.status(403).json({ success: false, error: 'Admin access required' });
    return;
  }
  next();
}

import crypto from 'crypto';

import type { NextFunction, Request, Response } from 'express';

import { db } from '../db/client';
import { idempotencyKeys } from '../db/schema';

const IDEMPOTENCY_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

export async function idempotencyMiddleware(
  req: Request & { user?: { id: string } },
  res: Response,
  next: NextFunction,
): Promise<void> {
  const key = req.headers['idempotency-key'] as string | undefined;
  if (!key || !['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
    next();
    return;
  }

  const userId = req.user?.id ?? 'anonymous';

  try {
    const existing = await db.query.idempotencyKeys.findFirst({
      where: (t, { eq, and }) =>
        and(eq(t.key, key), eq(t.userId, userId)),
    });

    if (existing?.responseBody) {
      res.status(existing.responseStatus ?? 200).json(JSON.parse(existing.responseBody));
      return;
    }

    const expiresAt = new Date(Date.now() + IDEMPOTENCY_TTL_MS);
    const id = crypto.randomUUID();

    await db.insert(idempotencyKeys).values({
      id,
      key,
      userId,
      method: req.method,
      path: req.path,
      expiresAt,
    });

    const originalJson = res.json.bind(res);
    res.json = (body) => {
      const result = originalJson(body);
      void db
        .update(idempotencyKeys)
        .set({ responseStatus: res.statusCode, responseBody: JSON.stringify(body) })
        .where((t: typeof idempotencyKeys.$inferSelect, { eq }: { eq: (a: unknown, b: unknown) => unknown }) =>
          eq(t.id, id),
        )
        .catch(() => {});
      return result;
    };

    next();
  } catch {
    next();
  }
}

import { Router } from 'express';

import { checkDbConnection } from '../db/client';

const router = Router();

const startTime = Date.now();

router.get('/health', async (_req, res) => {
  const dbOk = await checkDbConnection();

  const status = dbOk ? 'ok' : 'degraded';
  const httpStatus = dbOk ? 200 : 503;

  res.status(httpStatus).json({
    status,
    db: dbOk ? 'ok' : 'error',
    version: process.env.npm_package_version ?? '0.0.1',
    uptime_ms: Date.now() - startTime,
    timestamp: new Date().toISOString(),
  });
});

