import pino from 'pino';

import { env } from './env';

function buildLogger() {
  if (env.NODE_ENV !== 'production') {
    try {
      require.resolve('pino-pretty');
      return pino({
        level: 'debug',
        transport: {
          target: 'pino-pretty',
          options: { colorize: true, translateTime: 'SYS:standard', ignore: 'pid,hostname' },
        },
      });
    } catch {
      // pino-pretty not available; fall through to plain JSON logger
    }
  }

  return pino({ level: env.NODE_ENV === 'production' ? 'info' : 'debug' });
}

export const logger = buildLogger();

import crypto from 'crypto';

import jwt from 'jsonwebtoken';

import { env } from './env';

export interface AccessTokenPayload {
  sub: string;
  role: string;
  type: 'access';
}

export interface RefreshTokenPayload {
  sub: string;
  sessionId: string;
  type: 'refresh';
}

export interface WsTokenPayload {
  sub: string;
  type: 'ws';
}

export function signAccessToken(userId: string, role: string): string {
  return jwt.sign(
    { sub: userId, role, type: 'access' } satisfies AccessTokenPayload,
    env.JWT_SECRET,
    { expiresIn: env.JWT_EXPIRES_IN },
  );
}

export function signRefreshToken(userId: string, sessionId: string): string {
  return jwt.sign(
    { sub: userId, sessionId, type: 'refresh' } satisfies RefreshTokenPayload,
    env.JWT_REFRESH_SECRET,
    { expiresIn: env.JWT_REFRESH_EXPIRES_IN },
  );
}

export function signWsToken(userId: string): string {
  return jwt.sign(
    { sub: userId, type: 'ws' } satisfies WsTokenPayload,
    env.JWT_SECRET,
    { expiresIn: '10m' },
  );
}

export function verifyAccessToken(token: string): AccessTokenPayload {
  return jwt.verify(token, env.JWT_SECRET) as AccessTokenPayload;
}

export function verifyRefreshToken(token: string): RefreshTokenPayload {
  return jwt.verify(token, env.JWT_REFRESH_SECRET) as RefreshTokenPayload;
}

export function verifyWsToken(token: string): WsTokenPayload {
  return jwt.verify(token, env.JWT_SECRET) as WsTokenPayload;
}

export function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

export function generateSecureToken(bytes = 32): string {
  return crypto.randomBytes(bytes).toString('hex');
}

import { env } from '../lib/env';
import { logger } from '../lib/logger';

interface SendEmailOpts {
  to: string;
  subject: string;
  html: string;
  text?: string;
}

async function sendViaResend(opts: SendEmailOpts): Promise<void> {
  if (!env.RESEND_API_KEY) throw new Error('RESEND_API_KEY not configured');
  const { Resend } = await import('resend');
  const resend = new Resend(env.RESEND_API_KEY);
  const { error } = await resend.emails.send({
    from: 'Roamera <noreply@roamera.in>',
    to: opts.to,
    subject: opts.subject,
    html: opts.html,
    text: opts.text,
  });
  if (error) throw new Error(error.message);
}

async function sendViaNodemailer(opts: SendEmailOpts): Promise<void> {
  const nodemailer = await import('nodemailer');
  const transport = nodemailer.createTransport({
    host: process.env.SMTP_HOST ?? 'smtp.gmail.com',
    port: Number(process.env.SMTP_PORT ?? 587),
    auth: {
      user: process.env.SMTP_USER,
      pass: process.env.SMTP_PASS,
    },
  });
  await transport.sendMail({
    from: process.env.SMTP_FROM ?? `"Roamera" <${process.env.SMTP_USER}>`,
    to: opts.to,
    subject: opts.subject,
    html: opts.html,
    text: opts.text,
  });
}

export async function sendEmail(opts: SendEmailOpts): Promise<void> {
  if (env.NODE_ENV === 'development' && !env.RESEND_API_KEY) {
    logger.info({ to: opts.to, subject: opts.subject }, '[DEV] Email not sent — no RESEND_API_KEY');
    logger.debug({ html: opts.html }, '[DEV] Email body');
    return;
  }
  try {
    await sendViaResend(opts);
  } catch (e) {
    logger.warn({ err: e }, 'Resend failed, trying Nodemailer');
    await sendViaNodemailer(opts);
  }
}

// ─── Templates ───────────────────────────────────────────────────────────────

const BASE_URL = process.env.WEB_URL ?? 'http://localhost:3001';

export function emailVerifyTemplate(username: string, token: string): SendEmailOpts {
  const url = `${BASE_URL}/auth/verify-email?token=${token}`;
  return {
    to: '',
    subject: 'Verify your Roamera email',
    html: `
      <div style="font-family:Inter,sans-serif;max-width:480px;margin:0 auto;padding:24px">
        <h1 style="color:#0d9488;margin-bottom:8px">Roamera 🧭</h1>
        <p>Hi <strong>${username}</strong>,</p>
        <p>Click the link below to verify your email address. It expires in 24 hours.</p>
        <a href="${url}" style="display:inline-block;background:#0d9488;color:#fff;padding:12px 24px;border-radius:16px;text-decoration:none;font-weight:600;margin:16px 0">Verify Email</a>
        <p style="color:#64748b;font-size:13px">Or paste this link in your browser:<br/>${url}</p>
        <hr style="border-color:#e2e8f0;margin:24px 0"/>
        <p style="color:#94a3b8;font-size:12px">If you didn't sign up for Roamera, you can safely ignore this email.</p>
      </div>`,
    text: `Verify your Roamera email: ${url}`,
  };
}

export function otpTemplate(code: string): SendEmailOpts {
  return {
    to: '',
    subject: `${code} — your Roamera login code`,
    html: `
      <div style="font-family:Inter,sans-serif;max-width:480px;margin:0 auto;padding:24px">
        <h1 style="color:#0d9488;margin-bottom:8px">Roamera 🧭</h1>
        <p>Your one-time login code:</p>
        <div style="font-size:40px;font-weight:800;letter-spacing:12px;color:#0d9488;padding:16px 0">${code}</div>
        <p style="color:#64748b;font-size:13px">This code expires in 10 minutes.</p>
        <hr style="border-color:#e2e8f0;margin:24px 0"/>
        <p style="color:#94a3b8;font-size:12px">If you didn't request this, you can safely ignore it.</p>
      </div>`,
    text: `Your Roamera login code is: ${code}. It expires in 10 minutes.`,
  };
}

export function passwordResetTemplate(username: string, token: string): SendEmailOpts {
  const url = `${BASE_URL}/auth/reset-password?token=${token}`;
  return {
    to: '',
    subject: 'Reset your Roamera password',
    html: `
      <div style="font-family:Inter,sans-serif;max-width:480px;margin:0 auto;padding:24px">
        <h1 style="color:#0d9488;margin-bottom:8px">Roamera 🧭</h1>
        <p>Hi <strong>${username}</strong>,</p>
        <p>Click below to reset your password. This link expires in 1 hour.</p>
        <a href="${url}" style="display:inline-block;background:#0d9488;color:#fff;padding:12px 24px;border-radius:16px;text-decoration:none;font-weight:600;margin:16px 0">Reset Password</a>
        <p style="color:#64748b;font-size:13px">Or paste this link:<br/>${url}</p>
        <hr style="border-color:#e2e8f0;margin:24px 0"/>
        <p style="color:#94a3b8;font-size:12px">If you didn't request a password reset, ignore this email.</p>
      </div>`,
    text: `Reset your Roamera password: ${url}`,
  };
}

